            <div><Status :success="result.is_success" /><h2 class="mt-2 text-3xl font-semibold uppercase text-slate-950">{{ result.vehicle_number }}</h2><p class="mt-1 text-sm font-semibold text-slate-500">{{ result.created_at }} / Charged {{ money(result.charge) }}</p></div>
            <div class="flex gap-2"><a v-if="actions.pdf" :href="actions.pdf" class="rounded-lg bg-red-600 px-4 py-3 text-sm font-semibold text-white">Download PDF</a><Link :href="actions.index" class="rounded-lg border border-slate-200 px-4 py-3 text-sm font-semibold text-slate-700">Back</Link></div>
        </section>
