        <section v-for="section in sections" :key="section.title" class="mt-5 rounded-lg border border-slate-200 bg-white p-5 shadow-sm"><h3 class="text-xl font-semibold text-slate-950">{{ section.title }}</h3><dl class="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-3"><div v-for="item in section.items" :key="item.label" class="rounded-lg bg-slate-50 p-3"><dt class="text-xs font-semibold uppercase tracking-wide text-slate-500">{{ item.label }}</dt><dd class="mt-1 break-words text-sm font-semibold text-slate-950">{{ display(item.value) }}</dd></div></dl></section>
