<script setup lang="ts">import{defineComponent,h}from'vue';import{Head,Link}from'@inertiajs/vue3';import DealerLayout from '@/Layouts/DealerLayout.vue';defineProps<{page:any;result:any;summary:Array<any>;sections:Array<any>;columns:Array<any>;records:Array<any>;actions:{index:string;pdf:string|null}}>();const display=(v:any)=>v===null||v===undefined||v===''?'N/A':typeof v==='boolean'?(v?'Yes':'No'):String(v);const money=(v:number)=>`Rs ${new Intl.NumberFormat('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2}).format(Number(v||0))}`;const Status=defineComponent({props:{success:{type:Boolean,required:true}},setup(p){return()=>h('span',{class:['inline-flex rounded-md px-2.5 py-1 text-xs font-semibold',p.success?'bg-teal-50 text-teal-700':'bg-red-50 text-red-700']},p.success?'Verified':'Failed');}});const Metric=defineComponent({props:{label:{type:String,required:true},value:{type:[String,Number],required:true}},setup(p){return()=>h('div',{class:'rounded-lg border border-slate-200 bg-white p-4 shadow-sm'},[h('p',{class:'text-2xl font-semibold text-slate-950'},p.value),h('p',{class:'mt-1 text-xs font-semibold uppercase tracking-wide text-slate-500'},p.label)]);}});</script>
